parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "match_score": {
      "type": "number",
      "description": "ATS compatibility score from 0 to 100"
    },
    "matching_skills": {
      "type": "array",
      "description": "Skills found in both the resume and the job description",
      "items": {
        "type": "string"
      }
    },
    "missing_skills": {
      "type": "array",
      "description": "Important skills required by the job but missing from the resume",
      "items": {
        "type": "string"
      }
    },
    "strengths": {
      "type": "array",
      "description": "Candidate's strongest qualifications",
      "items": {
        "type": "string"
      }
    },
    "weaknesses": {
      "type": "array",
      "description": "Areas where the candidate is weaker compared to the job requirements",
      "items": {
        "type": "string"
      }
    },
    "recommendations": {
      "type": "array",
      "description": "Specific improvements the candidate should make to increase ATS compatibility",
      "items": {
        "type": "string"
      }
    },
    "interview_recommendation": {
      "type": "string",
      "enum": [
        "Highly Recommended",
        "Recommended",
        "Consider",
        "Not Recommended"
      ]
    },
    "overall_assessment": {
      "type": "string",
      "description": "Professional summary explaining the overall fit for the role"
    }
  },
  "required": [
    "match_score",
    "matching_skills",
    "missing_skills",
    "strengths",
    "weaknesses",
    "recommendations",
    "interview_recommendation",
    "overall_assessment"
  ]
}
